import { CallbackManager } from 'flowise';

const piiPatterns = [
  /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
  /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g,
  /\b\d{16}\b/g
];

export class PIIFlowiseCallback extends CallbackManager {
  async onChainEnd(inputs: any, outputs: any, runId: string) {
    const outputText = outputs.text || outputs.output || JSON.stringify(outputs);
    const piiMatches = piiPatterns.flatMap(pattern => 
      (outputText.match(pattern) || []).map(match => ({pattern, match}))
    );

    if (piiMatches.length > 0) {
      console.error(`[PII DETECTED] Run ${runId}:`, piiMatches);
      throw new Error(`PII found in chain output: ${piiMatches.map(m => m.match).join(', ')}`);
    }
  }

  async onRetrieverEnd(documents: any[], runId: string) {
    documents.forEach((doc, i) => {
      const content = doc.pageContent || doc.content;
      const piiMatches = piiPatterns.flatMap(pattern => 
        (content.match(pattern) || []).map(match => match)
      );
      if (piiMatches.length > 0) {
        console.warn(`[PII IN DOC] Doc ${i}:`, piiMatches);
      }
    });
  }
}

import { Tool } from 'flowise';

export class SecureCustomTool extends Tool {
  name = 'secure-tool';
  description = 'PII-safe custom tool';

  private piiRegex = /\b(?:[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}|\d{3}[-.]?\d{3}[-.]?\d{4})\b/g;

  async _call(input: string, callbacks: any) {
    const piiMatches = input.match(this.piiRegex);
    if (piiMatches) {
      callbacks.handleLog(`[PII BLOCKED] ${piiMatches.join(', ')}`);
      return `Input contains sensitive data: ${piiMatches.length} matches found. Scrubbed response.`;
    }

    // Original tool logic
    return await this.originalCall(input);
  }
}

import { VectorStoreRetriever } from 'flowise';

export class PIIAwareRetriever extends VectorStoreRetriever {
  private piiPatterns = [
    /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/gi,
    /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g
  ];

  async getRelevantDocuments(query: string): Promise<any[]> {
    const docs = await super.getRelevantDocuments(query);

    const auditResults = docs.map((doc, index) => {
      const content = doc.pageContent || doc.content;
      const matches = this.piiPatterns.flatMap(p => 
        (content.match(p) || []).map(m => m)
      );
      return { index, doc, piiCount: matches.length, samples: matches.slice(0, 3) };
    }).filter(r => r.piiCount > 0);

    if (auditResults.length > 0) {
      console.error('[VECTOR STORE PII]', auditResults);
    }

    return docs;
  }
}

