import { BaseChatModel } from 'flowise';

export class PIIFilterNode {
  private scrubber = {
    email: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/gi,
    phone: /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g,
    ssn: /\b\d{3}-?\d{2}-?\d{4}\b/g
  };

  filter(content: string): string {
    let cleaned = content;
    Object.entries(this.scrubber).forEach(([type, pattern]) => {
      cleaned = cleaned.replace(pattern, `[${type.toUpperCase()}_REDACTED]`);
    });
    return cleaned;
  }

  async processInput(input: any): Promise<any> {
    if (typeof input === 'string') {
      return this.filter(input);
    }
    if (input.text) {
      input.text = this.filter(input.text);
    }
    return input;
  }
}

import { AgentExecutor } from 'flowise';

export class SecureAgentExecutor extends AgentExecutor {
  private piiRedactor = /\b(?:[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}|\d{3}[-.]?\d{3}[-.]?\d{4})\b/gi;

  async invoke(input: any, config?: any) {
    // Scrub input before agent processing
    const safeInput = {
      ...input,
      input: input.input.replace(this.piiRedactor, '[REDACTED]')
    };

    const result = await super.invoke(safeInput, config);

    // Scrub output before returning
    return {
      ...result,
      output: result.output.replace(this.piiRedactor, '[REDACTED]')
    };
  }

  async handoffContext(fromAgent: string, toAgent: string, context: any) {
    return {
      ...context, 
      memory: this.scrubMemory(context.memory)
    };
  }
}

import { DocumentLoader } from 'flowise';

export class SecureDocumentLoader extends DocumentLoader {
  private piiReplacements = {
    email: '[EMAIL_REDACTED]',
    phone: '[PHONE_REDACTED]',
    creditCard: '[CARD_REDACTED]'
  };

  async loadAndSplit(): Promise<any[]> {
    const docs = await super.loadAndSplit();

    return docs.map(doc => {
      let content = doc.pageContent;

      // Apply PII redaction
      content = content.replace(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/gi, this.piiReplacements.email);
      content = content.replace(/\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, this.piiReplacements.phone);
      content = content.replace(/\b\d{16}\b/g, this.piiReplacements.creditCard);

      return {
        ...doc,
        pageContent: content,
        metadata: { ...doc.metadata, pii_scrubbed: true }
      };
    });
  }
}

