import { Vex } from '@vex_dev/sdk';
import { FlowiseChatflow } from 'flowise';

// Initialize Vex with Flowise integration
const vex = new Vex({
  projectId: 'your-project-id',
  integrations: {
    flowise: {
      enabled: true,
      piiRules: ['email', 'phone', 'ssn', 'credit_card'],
      autoRemediate: true
    }
  }
});

// Add Vex as callback handler to Flowise chatflow
const chatflow = new FlowiseChatflow({
  // your flow config
});

chatflow.callbackManager.addHandler({
  handleChainStart: (chain, inputs) => {
    vex.track('flowise.chain_start', { inputs });
  },

  handleChainEnd: async (outputs, runId) => {
    const issues = await vex.detectPII(outputs);
    if (issues.length > 0) {
      await vex.blockPII(runId, issues);
      throw new Error('Vex: PII detected and blocked');
    }
  },

  handleRetrieverEnd: (documents) => {
    vex.scanDocuments(documents, 'vector_retrieval');
  }
});

// Vex auto-generates remediation
vex.on('pii_fix_available', async (fix) => {
  console.log('Vex PII Fix:', fix.code);
  await vex.applyFix(fix);
});
